    engQ: 30, engMin: 15,
    banca: [{"s": "Matematica di base", "q": "Qual è la soluzione dell'equazione 2x² - 7x + 3 = 0?", "o": ["x=1/2, x=3", "x= -1/2, x=3", "x=1/2, x= -3", "x= -1/2, x= -3", "x=2, x=3"], "c": 0}, {"s": "Matematica di base", "q": "Un rettangolo ha perimetro di 48 cm e la sua base è il doppio dell'altezza. Qual è l'area del rettangolo?", "o": ["128 cm²", "108 cm²", "96 cm²", "144 cm²", "72 cm²"], "c": 0}, {"s": "Matematica di base", "q": "Qual è il dominio della funzione f(x) = √(x-3) + 1/(x-5)?", "o": ["x ≥ 3", "x > 3", "x ≥ 3 e x ≠ 5", "x ≠ 5", "x > 3 e x ≠ 5"], "c": 2}, {"s": "Matematica di base", "q": "Il prezzo di un articolo è aumentato del 20% e successivamente è stato scontato del 10% rispetto al nuovo prezzo. Se il prezzo finale è 108 euro, qual era il prezzo iniziale?", "o": ["100 euro", "90 euro", "110 euro", "105 euro", "120 euro"], "c": 0}, {"s": "Matematica di base", "q": "Se log₂(x) = 3, quanto vale x?", "o": ["6", "8", "9", "16", "1/8"], "c": 1}, {"s": "Matematica di base", "q": "In un'urna ci sono 5 palline rosse, 3 verdi e 2 blu. Qual è la probabilità di estrarre una pallina che non sia rossa?", "o": ["3/10", "1/2", "2/5", "7/10", "3/5"], "c": 1}, {"s": "Matematica di base", "q": "Qual è la distanza tra i punti A(1, -2) e B(4, 2) nel piano cartesiano?", "o": ["3", "4", "5", "√17", "√13"], "c": 2}, {"s": "Biologia", "q": "Quale delle seguenti strutture cellulari è responsabile principalmente della sintesi delle proteine destinate ad essere secrete fuori dalla cellula o inserite nella membrana plasmatica?", "o": ["Mitocondrio", "Lisosoma", "Ribosoma libero", "Reticolo endoplasmatico rugoso", "Apparato di Golgi"], "c": 3}, {"s": "Biologia", "q": "Se un individuo eterozigote per un singolo gene (Aa) si incrocia con un individuo omozigote recessivo (aa), quale sarà la percentuale di prole eterozigote?", "o": ["0%", "25%", "50%", "75%", "100%"], "c": 2}, {"s": "Biologia", "q": "Quale ormone è prodotto dalle isole di Langerhans nel pancreas e abbassa il livello di glucosio nel sangue?", "o": ["Glucagone", "Adrenalina", "Insulina", "Cortisolo", "Tiroxina"], "c": 2}, {"s": "Biologia", "q": "Quale processo evolutivo porta all'aumento della frequenza di alleli vantaggiosi in una popolazione nel corso del tempo?", "o": ["Deriva genetica", "Mutazione", "Flusso genico", "Selezione naturale", "Reincrocio"], "c": 3}, {"s": "Biologia", "q": "Dove avviene la fase luminosa della fotosintesi nelle piante?", "o": ["Stroma del cloroplasto", "Matrice del mitocondrio", "Tilacoidi del cloroplasto", "Citoplasma", "Membrana interna del mitocondrio"], "c": 2}, {"s": "Biologia", "q": "Quale tipo di tessuto connettivo è caratterizzato da una matrice extracellulare liquida e trasporta ossigeno, nutrienti e ormoni?", "o": ["Tessuto adiposo", "Tessuto cartilagineo", "Tessuto osseo", "Sangue", "Tessuto connettivo lasso"], "c": 3}, {"s": "Biologia", "q": "Durante quale fase della mitosi i cromatidi fratelli si separano e migrano verso i poli opposti della cellula?", "o": ["Profase", "Metafase", "Anafase", "Telofase", "Interfase"], "c": 2}, {"s": "Fisica", "q": "Un'auto parte da ferma e raggiunge una velocità di 20 m/s in 5 secondi, mantenendo un'accelerazione costante. Qual è la distanza percorsa dall'auto in questo intervallo di tempo?", "o": ["50 m", "100 m", "25 m", "75 m", "40 m"], "c": 0}, {"s": "Fisica", "q": "Una forza di 30 N agisce su un oggetto di massa 5 kg. Qual è l'accelerazione dell'oggetto?", "o": ["0.17 m/s²", "6 m/s²", "150 m/s²", "5 m/s²", "30 m/s²"], "c": 1}, {"s": "Fisica", "q": "Un corpo di massa 2 kg cade da un'altezza di 10 m. Qual è la sua energia cinetica appena prima di toccare terra (si trascuri l'attrito dell'aria, g = 9.8 m/s²)?", "o": ["19.6 J", "98 J", "196 J", "9.8 J", "39.2 J"], "c": 2}, {"s": "Fisica", "q": "Quante calorie sono necessarie per aumentare la temperatura di 50 g d'acqua da 20 °C a 60 °C? (Calore specifico dell'acqua = 1 cal/g°C)", "o": ["200 cal", "500 cal", "1000 cal", "2000 cal", "2500 cal"], "c": 3}, {"s": "Fisica", "q": "Una resistenza di 10 Ω è attraversata da una corrente di 2 A. Qual è la differenza di potenziale ai capi della resistenza?", "o": ["0.2 V", "5 V", "10 V", "20 V", "12 V"], "c": 3}, {"s": "Fisica", "q": "Un'onda sonora ha una frequenza di 440 Hz e viaggia nell'aria a una velocità di 340 m/s. Qual è la sua lunghezza d'onda?", "o": ["0.77 m", "1.29 m", "149.6 m", "780 m", "340 m"], "c": 0}, {"s": "Fisica", "q": "Un corpo galleggia se la sua densità è minore o uguale alla densità del fluido in cui è immerso. Quale principio fisico descrive la spinta verso l'alto esercitata da un fluido su un corpo immerso?", "o": ["Principio di Pascal", "Legge di Stevino", "Principio di Bernoulli", "Principio di Archimede", "Legge di Hooke"], "c": 3}, {"s": "Chimica", "q": "Un isotopo di un elemento si differenzia da un altro isotopo dello stesso elemento per il numero di:", "o": ["Protoni", "Elettroni", "Neutroni", "Livelli energetici", "Carica nucleare"], "c": 2}, {"s": "Chimica", "q": "Quale tipo di legame si forma tra un atomo di sodio (Na) e un atomo di cloro (Cl)?", "o": ["Covalente puro", "Covalente polare", "Ionico", "Metallico", "A idrogeno"], "c": 2}, {"s": "Chimica", "q": "Quante moli di acqua (H₂O) si formano dalla reazione completa di 2 moli di idrogeno (H₂) con ossigeno (O₂)? (Reazione: 2H₂ + O₂ → 2H₂O)", "o": ["1 mole", "2 moli", "3 moli", "4 moli", "0.5 moli"], "c": 1}, {"s": "Chimica", "q": "Qual è la molarità di una soluzione preparata sciogliendo 196 g di acido solforico (H₂SO₄) in acqua fino a un volume finale di 2 litri? (Massa molare H₂SO₄ = 98 g/mol)", "o": ["0.5 M", "1 M", "2 M", "0.25 M", "1.5 M"], "c": 1}, {"s": "Chimica", "q": "Una soluzione con pH 2 è:", "o": ["Fortemente basica", "Debolmente basica", "Neutra", "Debolmente acida", "Fortemente acida"], "c": 4}, {"s": "Chimica", "q": "Quale delle seguenti è una reazione di ossido-riduzione?", "o": ["HCl + NaOH → NaCl + H₂O", "CaCO₃ → CaO + CO₂", "Zn + CuSO₄ → ZnSO₄ + Cu", "Ag⁺ + Cl⁻ → AgCl", "H₂O + CO₂ → H₂CO₃"], "c": 2}, {"s": "Chimica", "q": "Quale gruppo funzionale è caratteristico degli alcoli?", "o": ["-COOH", "-CHO", "-OH", "-NH₂", "-CO-"], "c": 2}],
