    banca: [{"s": "Matematica di base", "q": "Qual è il valore di x che soddisfa l'equazione 3^(x+1) = 27^(x-1)?", "o": ["x = 1", "x = 2", "x = 3/2", "x = 1/2", "x = 0"], "c": 2}, {"s": "Matematica di base", "q": "Data la funzione f(x) = |x-2| + 3, qual è il suo valore minimo?", "o": ["0", "1", "2", "3", "5"], "c": 3}, {"s": "Matematica di base", "q": "Se log₂(x) = 3 e log₃(y) = 2, qual è il valore di x + y?", "o": ["12", "15", "17", "18", "20"], "c": 2}, {"s": "Matematica di base", "q": "Qual è l'area di un cerchio la cui circonferenza è 10π?", "o": ["10π", "20π", "25π", "50π", "100π"], "c": 2}, {"s": "Ragionamento, problemi e comprensione", "q": "Se tutti i cani sono animali e tutti gli animali hanno bisogno di ossigeno, quale delle seguenti affermazioni è necessariamente vera?", "o": ["Tutti gli animali sono cani.", "Alcuni animali non hanno bisogno di ossigeno.", "Tutti i cani hanno bisogno di ossigeno.", "Nessun cane ha bisogno di ossigeno.", "Solo i cani hanno bisogno di ossigeno."], "c": 2}, {"s": "Ragionamento, problemi e comprensione", "q": "Una vasca viene riempita da due rubinetti. Il primo rubinetto la riempie in 6 ore, il secondo in 3 ore. Se entrambi i rubinetti vengono aperti contemporaneamente, quanto tempo impiegheranno per riempire la vasca?", "o": ["1 ora", "1,5 ore", "2 ore", "2,5 ore", "3 ore"], "c": 2}, {"s": "Ragionamento, problemi e comprensione", "q": "Se 'sole' sta a 'giorno' come 'luna' sta a 'X', quale parola è 'X'?", "o": ["notte", "stelle", "oscurità", "sera", "marea"], "c": 0}, {"s": "Ragionamento, problemi e comprensione", "q": "In una sequenza numerica, il primo termine è 2, il secondo è 4, il terzo è 8. Qual è il sesto termine della sequenza se segue una logica moltiplicativa?", "o": ["16", "32", "64", "128", "256"], "c": 2}, {"s": "Biologia", "q": "Quale delle seguenti strutture cellulari è responsabile della sintesi delle proteine?", "o": ["Mitocondrio", "Nucleo", "Ribosoma", "Apparato di Golgi", "Lisosoma"], "c": 2}, {"s": "Biologia", "q": "Qual è il processo attraverso cui le piante convertono l'energia luminosa in energia chimica?", "o": ["Respirazione cellulare", "Fermentazione", "Fotosintesi", "Ciclo di Krebs", "Glicolisi"], "c": 2}, {"s": "Biologia", "q": "Quale tra i seguenti è un esempio di monosaccaride?", "o": ["Saccarosio", "Lattosio", "Amido", "Glucosio", "Glicogeno"], "c": 3}, {"s": "Biologia", "q": "Quale ormone è principalmente responsabile della regolazione dei livelli di zucchero nel sangue nell'uomo?", "o": ["Adrenalina", "Insulina", "Estrogeno", "Testosterone", "Tiroxina"], "c": 1}, {"s": "Biologia", "q": "Quale delle seguenti affermazioni riguardo al DNA è corretta?", "o": ["È un polimero di amminoacidi.", "Contiene l'uracile al posto della timina.", "La sua struttura è un singolo filamento.", "È il materiale genetico di tutti gli organismi viventi.", "Si trova esclusivamente nel citoplasma."], "c": 3}, {"s": "Chimica", "q": "Qual è il numero di ossidazione del cromo (Cr) nel composto K₂Cr₂O₇?", "o": ["+2", "+3", "+4", "+6", "+7"], "c": 3}, {"s": "Chimica", "q": "Quale tipo di legame si forma tra due atomi con una differenza di elettronegatività molto elevata (superiore a 1.7)?", "o": ["Covalente puro", "Covalente polare", "Ionico", "Metallico", "A idrogeno"], "c": 2}, {"s": "Chimica", "q": "Quanti grammi di NaOH (Massa molare ≈ 40 g/mol) sono necessari per preparare 500 mL di una soluzione 0.5 M?", "o": ["5 g", "10 g", "20 g", "40 g", "80 g"], "c": 1}, {"s": "Chimica", "q": "Quale delle seguenti sostanze è un acido secondo la definizione di Brønsted-Lowry?", "o": ["NH₃", "H₂O", "OH⁻", "HCl", "CO₃²⁻"], "c": 3}, {"s": "Chimica", "q": "Un isotopo di un elemento chimico differisce dall'elemento \"standard\" per il numero di:", "o": ["Protoni", "Elettroni", "Neutroni", "Gusci elettronici", "Legami chimici"], "c": 2}, {"s": "Fisica", "q": "Un corpo di massa 2 kg è sottoposto a una forza costante di 10 N. Qual è l'accelerazione del corpo?", "o": ["0.2 m/s²", "2 m/s²", "5 m/s²", "10 m/s²", "20 m/s²"], "c": 2}, {"s": "Fisica", "q": "Un oggetto cade da un'altezza di 45 m. Trascurando l'attrito dell'aria e usando g = 10 m/s², quanto tempo impiega per raggiungere il suolo?", "o": ["1 s", "2 s", "3 s", "4 s", "5 s"], "c": 2}, {"s": "Fisica", "q": "Qual è l'unità di misura della potenza nel Sistema Internazionale?", "o": ["Joule (J)", "Newton (N)", "Watt (W)", "Pascal (Pa)", "Volt (V)"], "c": 2}, {"s": "Fisica", "q": "Se un circuito ha una resistenza di 10 Ω e una corrente di 2 A, qual è la differenza di potenziale (tensione) ai capi della resistenza?", "o": ["0.2 V", "5 V", "10 V", "20 V", "50 V"], "c": 3}, {"s": "Fisica", "q": "Un'onda sonora si propaga nell'aria con una velocità di 340 m/s e ha una frequenza di 170 Hz. Qual è la sua lunghezza d'onda?", "o": ["0.5 m", "1 m", "2 m", "4 m", "8 m"], "c": 2}, {"s": "Scienze della Terra", "q": "Quale processo geologico è responsabile principalmente della formazione delle montagne di tipo alpino?", "o": ["Vulcanismo", "Erosione glaciale", "Tettonica a placche", "Sedimentazione", "Meteorizzazione"], "c": 2}, {"s": "Scienze della Terra", "q": "Quale dei seguenti gas è il più abbondante nell'atmosfera terrestre?", "o": ["Ossigeno", "Anidride carbonica", "Azoto", "Argon", "Vapore acqueo"], "c": 2}, {"s": "Scienze della Terra", "q": "La scala di Richter misura:", "o": ["La velocità del vento", "L'intensità delle piogge", "La magnitudo dei terremoti", "La temperatura dell'oceano", "L'altezza delle onde"], "c": 2}, {"s": "Scienze della Terra", "q": "Quale strato della Terra è prevalentemente allo stato liquido?", "o": ["Crosta terrestre", "Mantello superiore", "Mantello inferiore", "Nucleo esterno", "Nucleo interno"], "c": 3}, {"s": "Scienze della Terra", "q": "Quale fenomeno è causato dall'attrazione gravitazionale della Luna (e in minor parte del Sole) sugli oceani terrestri?", "o": ["Correnti oceaniche", "Tsunami", "Maree", "Venti", "Erosione costiera"], "c": 2}],
