export function tolcTotQ(t) { if (t.totQ) return t.totQ; const s = t.sezioni.reduce((a, x) => a + (x.q || 0), 0); return s || null; }
export function tolcTotMin(t) { const m = t.sezioni.reduce((a, x) => a + (x.min || 0), 0); return m || null; }
